ps.pstext:
if !IsFeatureImplemented(FEAT_SME2p3) then EndOfDecode(Decode_UNDEF); end;
if MaxImplementedAnyVL() < 512 then EndOfDecode(Decode_UNDEF); end;
let esize : integer{} = 16;
let isize : integer{} = 6;
let n : integer = UInt(Zn);
let m : integer = UInt(Zm);
let dstride : integer = 1;
let d : integer = UInt(Zd::'00');
let select : integer = UInt(i1);

if !IsFeatureImplemented(FEAT_SME2p3) then EndOfDecode(Decode_UNDEF); end;
if MaxImplementedAnyVL() < 512 then EndOfDecode(Decode_UNDEF); end;
let esize : integer{} = 16;
let isize : integer{} = 6;
let n : integer = UInt(Zn);
let m : integer = UInt(Zm);
let dstride : integer = 4;
let d : integer = UInt(D::'00'::Zd);
let select : integer = UInt(i1);

CheckStreamingSVEEnabled();
let VL : integer{} = CurrentVL();
if VL < 512 then EndOfDecode(Decode_UNDEF); end;
let elements : integer = VL DIV esize;
let operand : bits(2*VL) = Z{VL}((m+1) MOD 32) :: Z{VL}(m+0);
let idxsize : integer{} = VL + (VL DIV 2);
let idxpos : integer{}  = if select == 1 then (VL DIV 2) else 0;
let indexes : bits(idxsize) = operand[idxpos+:idxsize];
let table : bits(1024) = Z{VL}((n+1) MOD 32)[511:0] :: Z{VL}(n+0)[511:0];
var dst : integer = d;
var result : bits(VL);

for r = 0 to 3 do
    let base : integer = r * elements;
    for e = 0 to elements-1 do
        let index : integer = UInt(indexes[(base+e)*:isize]);
        result[e*:esize] = table[index*:esize];
    end;
    Z{VL}(dst) = result;
    dst = dst + dstride;
end;
